+//! Help overlay widget.
+//!
+//! Modal overlay showing keyboard shortcuts and navigation help.
+//! Uses ftui's Modal + Block + Paragraph for the primary rendering path,
+//! with ratatui legacy compat behind the `ui-legacy` feature gate.
+
+use ftui::text::{Line as FtuiLine, Span as FtuiSpan, Text as FtuiText};
+use ftui::widgets::block::Block as FtuiBlock;
+use ftui::widgets::modal::{Modal, ModalPosition, ModalSizeConstraints};
+use ftui::widgets::paragraph::Paragraph as FtuiParagraph;
+use ftui::widgets::Widget as FtuiWidget;
+use ftui::PackedRgba;
+use ftui::Style as FtuiStyle;
+
+#[cfg(feature = "ui-legacy")]
+use ratatui::{
+    buffer::Buffer,
+    layout::Rect,
+    style::{Color, Style},
+    widgets::{Block, Borders, Clear, Paragraph, Widget, Wrap},
+};
+
+use crate::tui::layout::Breakpoint;
+use crate::tui::theme::Theme;
+
+// ---------------------------------------------------------------------------
+// Help content
+// ---------------------------------------------------------------------------
+
+/// A single keybinding entry.
+#[derive(Debug, Clone)]
+struct Binding {
+    key: &'static str,
+    desc: &'static str,
+}
+
+/// A section of related keybindings.
+#[derive(Debug, Clone)]
+struct Section {
+    title: &'static str,
+    bindings: &'static [Binding],
+}
+
+const NAVIGATION: &[Binding] = &[
+    Binding { key: "j / Down", desc: "Move down" },
+    Binding { key: "k / Up", desc: "Move up" },
+    Binding { key: "Home", desc: "Go to top" },
+    Binding { key: "End", desc: "Go to bottom" },
+    Binding { key: "Ctrl+d", desc: "Page down" },
+    Binding { key: "Ctrl+u", desc: "Page up" },
+    Binding { key: "Tab", desc: "Cycle focus" },
+    Binding { key: "n / N", desc: "Next/prev match" },
+];
+
+const ACTIONS: &[Binding] = &[
+    Binding { key: "/", desc: "Start search" },
+    Binding { key: "Space", desc: "Toggle selection" },
+    Binding { key: "a", desc: "Select recommended" },
+    Binding { key: "A", desc: "Select all" },
+    Binding { key: "u", desc: "Unselect all" },
+    Binding { key: "x", desc: "Invert selection" },
+    Binding { key: "e", desc: "Execute action" },
+    Binding { key: "r", desc: "Refresh list" },
+    Binding { key: "Enter", desc: "Toggle detail pane" },
+    Binding { key: "s", desc: "Summary view" },
+    Binding { key: "t", desc: "Genealogy view" },
+    Binding { key: "g", desc: "Galaxy-brain view" },
+    Binding { key: "v", desc: "Toggle goal view" },
+];
+
+const GENERAL: &[Binding] = &[
+    Binding { key: "?", desc: "Toggle help" },
+    Binding { key: "q / Esc", desc: "Quit" },
+];
+
+const SECTIONS: &[Section] = &[
+    Section { title: "Navigation", bindings: NAVIGATION },
+    Section { title: "Actions", bindings: ACTIONS },
+    Section { title: "General", bindings: GENERAL },
+];
+
+/// Key column width for full layout.
+const KEY_COL_WIDTH: usize = 12;
+
+// ---------------------------------------------------------------------------
+// HelpOverlay widget
+// ---------------------------------------------------------------------------
+
+/// Help overlay widget showing keyboard shortcuts.
+#[derive(Debug)]
+pub struct HelpOverlay<'a> {
+    /// Theme for styling.
+    theme: Option<&'a Theme>,
+    /// Current breakpoint for adaptive layout.
+    breakpoint: Breakpoint,
+}
+
+impl<'a> Default for HelpOverlay<'a> {
+    fn default() -> Self {
+        Self::new()
+    }
+}
+
+impl<'a> HelpOverlay<'a> {
+    /// Create a new help overlay.
+    pub fn new() -> Self {
+        Self {
+            theme: None,
+            breakpoint: Breakpoint::Standard,
+        }
+    }
+
+    /// Set the theme.
+    pub fn theme(mut self, theme: &'a Theme) -> Self {
+        self.theme = Some(theme);
+        self
+    }
+
+    /// Set the breakpoint for adaptive layout.
+    pub fn breakpoint(mut self, breakpoint: Breakpoint) -> Self {
+        self.breakpoint = breakpoint;
+        self
+    }
+
+    // ── Content builders ──────────────────────────────────────────────
+
+    /// Build compact help text lines for small terminals.
+    pub fn build_compact_lines() -> Vec<FtuiLine> {
+        vec![
+            FtuiLine::raw("Navigation: j/k/Home/End"),
+            FtuiLine::raw("Search: /"),
+            FtuiLine::raw("Select: Space/a/A/u/x"),
+            FtuiLine::raw("Execute: e"),
+            FtuiLine::raw("Detail: Enter"),
+            FtuiLine::raw("Views: s/t/g  Mode: v"),
+            FtuiLine::raw("Help: ?  Quit: q"),
+        ]
+    }
+
+    /// Build full help text lines with formatted sections.
+    pub fn build_full_lines(theme: Option<&Theme>) -> Vec<FtuiLine> {
+        let title_style = theme
+            .map(|t| t.stylesheet().get_or_default("table.header"))
+            .unwrap_or_else(|| FtuiStyle::new().bold());
+
+        let key_style = theme
+            .map(|t| t.stylesheet().get_or_default("table.selected"))
+            .unwrap_or_else(|| {
+                FtuiStyle::new()
+                    .fg(PackedRgba::rgb(0, 255, 255))
+                    .bold()
+            });
+
+        let desc_style = theme
+            .map(|t| {
+                let sheet = t.stylesheet();
+                sheet.get_or_default("border.normal")
+            })
+            .unwrap_or_default();
+
+        let mut lines = Vec::new();
+
+        // Title
+        lines.push(FtuiLine::from_spans([FtuiSpan::styled(
+            "  Process Triage TUI Help",
+            title_style,
+        )]));
+        lines.push(FtuiLine::raw(""));
+
+        for section in SECTIONS {
+            // Section header
+            lines.push(FtuiLine::from_spans([FtuiSpan::styled(
+                format!("  {}:", section.title),
+                title_style,
+            )]));
+
+            for binding in section.bindings {
+                let padded_key = format!("    {:width$}", binding.key, width = KEY_COL_WIDTH);
+                lines.push(FtuiLine::from_spans([
+                    FtuiSpan::styled(padded_key, key_style),
+                    FtuiSpan::styled(binding.desc, desc_style),
+                ]));
+            }
+
+            lines.push(FtuiLine::raw(""));
+        }
+
+        lines
+    }
+
+    // ── ftui rendering ────────────────────────────────────────────────
+
+    /// Render the help overlay using ftui Modal + Paragraph.
+    pub fn render_ftui(
+        &self,
+        area: ftui::layout::Rect,
+        frame: &mut ftui::render::frame::Frame,
+    ) {
+        let lines = match self.breakpoint {
+            Breakpoint::Minimal => Self::build_compact_lines(),
+            _ => Self::build_full_lines(self.theme),
+        };
+
+        let border_style = self
+            .theme
+            .map(|t| t.stylesheet().get_or_default("border.focused"))
+            .unwrap_or_else(|| FtuiStyle::new().fg(PackedRgba::rgb(0, 255, 255)));
+
+        let text_style = self
+            .theme
+            .map(|t| {
+                let sheet = t.stylesheet();
+                sheet.get_or_default("border.normal")
+            })
+            .unwrap_or_default();
+
+        let block = FtuiBlock::bordered()
+            .title(" Help ")
+            .border_style(border_style);
+
+        let text: FtuiText = lines.into_iter().collect();
+        let paragraph = FtuiParagraph::new(text).style(text_style).block(block);
+
+        // Size constraints: 50% width, 60% height (matching current app.rs usage)
+        let size = ModalSizeConstraints::new()
+            .min_width(30)
+            .max_width((area.width as f32 * 0.5) as u16)
+            .min_height(10)
+            .max_height((area.height as f32 * 0.6) as u16);
+
+        let modal = Modal::new(paragraph)
+            .position(ModalPosition::Center)
+            .size(size);
+
+        FtuiWidget::render(&modal, area, frame);
+    }
+
+    // ── Legacy ratatui rendering ──────────────────────────────────────
+
+    /// Build compact help string for legacy rendering.
+    #[cfg(feature = "ui-legacy")]
+    fn compact_help_text() -> &'static str {
+        concat!(
+            "Navigation: j/k/Home/End\n",
+            "Search: /\n",
+            "Select: Space/a/A/u/x\n",
+            "Execute: e\n",
+            "Detail: Enter\n",
+            "Views: s/t/g  Mode: v\n",
+            "Help: ?  Quit: q",
+        )
+    }
+
+    /// Build full help string for legacy rendering.
+    #[cfg(feature = "ui-legacy")]
+    fn full_help_text() -> String {
+        let mut text = String::from("  Process Triage TUI Help\n\n");
+        for section in SECTIONS {
+            text.push_str(&format!("  {}:\n", section.title));
+            for binding in section.bindings {
+                text.push_str(&format!(
+                    "    {:width$}{}\n",
+                    binding.key,
+                    binding.desc,
+                    width = KEY_COL_WIDTH,
+                ));
+            }
+            text.push('\n');
+        }
+        text
+    }
+}
+
+// ---------------------------------------------------------------------------
+// Legacy ratatui Widget (behind feature gate)
+// ---------------------------------------------------------------------------
+
+#[cfg(feature = "ui-legacy")]
+impl<'a> Widget for HelpOverlay<'a> {
+    fn render(self, area: Rect, buf: &mut Buffer) {
+        let help_text = match self.breakpoint {
+            Breakpoint::Minimal => Self::compact_help_text().to_string(),
+            _ => Self::full_help_text(),
+        };
+
+        let border_style = if let Some(theme) = self.theme {
+            theme.style_border_focused()
+        } else {
+            Style::default().fg(Color::Cyan)
+        };
+
+        let text_style = if let Some(theme) = self.theme {
+            theme.style_normal()
+        } else {
+            Style::default()
+        };
+
+        let block = Block::default()
+            .borders(Borders::ALL)
+            .title(" Help ")
+            .border_style(border_style);
+
+        // Clear background
+        Clear.render(area, buf);
+
+        let paragraph = Paragraph::new(help_text)
+            .block(block)
+            .style(text_style)
+            .wrap(Wrap { trim: false });
+
+        paragraph.render(area, buf);
+    }
+}
+
